return [{ json: { sourceBatch: 'portfolio-knowledge-demo-001', processingMode: 'deterministic', selectedOllamaModel: null, documents: [
  { document_id: 'doc-local-ai-001', title: 'PostgreSQL Import Reliability Notes', source: 'local-sample', text: 'Use idempotent upserts, audit records, and rejection logs for import workflows. Keep credentials out of workflow JSON. Verify row counts after each execution.' },
  { document_id: 'doc-local-ai-002', title: 'n8n Community Draft Ideas', source: 'local-sample', text: 'Share a practical case study about self-hosted n8n, PostgreSQL persistence, Docker and Colima debugging, and local-first workflow evidence.' },
  { document_id: 'doc-local-ai-003', title: 'Operations Runbook Fragment', source: 'local-sample', text: 'Before changing a workflow, take a local backup. After execution, run health checks, query reports, and secret scans before publishing artifacts.' }
] } }];

const documents = ($json.documents || []).map((doc) => {
  const text = doc.text || '';
  const words = text.split(/\s+/).filter(Boolean);
  const topic = /postgres|upsert|row count|credential/i.test(text) ? 'workflow reliability' : /community|case study|feedback/i.test(text) ? 'community publishing' : 'operations runbook';
  return { ...doc, word_count: words.length, topic, document_type: 'note' };
});
return [{ json: { ...$json, documents } }];

const classified = ($json.documents || []).map((doc) => {
  const text = `${doc.title} ${doc.text}`.toLowerCase();
  let classification = 'general-knowledge';
  let confidence = 0.72;
  if (text.includes('postgres') || text.includes('workflow')) { classification = 'technical-automation'; confidence = 0.91; }
  if (text.includes('community') || text.includes('case study')) { classification = 'community-content'; confidence = 0.86; }
  if (text.includes('runbook') || text.includes('backup')) { classification = 'operations-procedure'; confidence = 0.88; }
  return { ...doc, classification, confidence };
});
return [{ json: { ...$json, documents: classified } }];

const structuredDocuments = ($json.documents || []).map((doc) => {
  const sentences = String(doc.text || '').split(/(?<=[.!?])\s+/).filter(Boolean);
  return {
    document_id: doc.document_id,
    title: doc.title,
    source: doc.source,
    document_type: doc.document_type,
    topic: doc.topic,
    classification: doc.classification,
    confidence: doc.confidence,
    summary: sentences.slice(0, 2).join(' '),
    key_points: sentences.slice(0, 4),
    action_items: sentences.filter((sentence) => /run|verify|keep|share|take|scan/i.test(sentence)).slice(0, 5),
    review_required: doc.confidence < 0.85,
    processing_mode: $json.processingMode,
    raw_document: doc
  };
});
return [{ json: { ...$json, structuredDocuments, recordsPersisted: structuredDocuments.length, reviewRequiredCount: structuredDocuments.filter((doc) => doc.review_required).length } }];

